function getTypeImg(type) {
	return new Promise((res, rej) => {
		uni.request({
			url: 'http://127.0.0.1:8080/get_type',
			data: {
				type
			},
			method: 'GET',
			success: (resData) => {
				res(resData.data)
			},
			fail: (err) => {
				rej(err);
				console.log(err);
			}
		});
	});
	//console.log(Imgs);
};
export {
	getTypeImg
}